const j = $json;

// Si no hay topic seleccionado, corta aquí
if (!j.id) return [];

// Resumen corto para no meter tronchos al prompt
const summary = (j.original_summary || "").toString().replace(/\s+/g, " ").trim();
const shortSummary = summary.length > 500 ? summary.slice(0, 500) + "..." : summary;

return [
  {
    json: {
      valid: true,
      topic_id: j.id,
      fecha_digest: j.fecha_digest ?? null,
      rank_dia: j.rank_dia ?? null,

      original_title: j.original_title ?? "",
      original_summary: shortSummary,
      original_url: j.original_url ?? "",

      tipo_contenido: j.tipo_contenido ?? "",
      prioridad: j.prioridad ?? null,
      potencial_linkedin: j.potencial_linkedin ?? null,
      potencial_seo: j.potencial_seo ?? null,
      potencial_nexprix: j.potencial_nexprix ?? null,
      riesgo_reputacional: j.riesgo_reputacional ?? "",
      angulo_recomendado: j.angulo_recomendado ?? "",

      // Prompt base para Basic LLM Chain
      reactor_input: [
        `Título: ${j.original_title ?? ""}`,
        `Resumen: ${shortSummary}`,
        `URL: ${j.original_url ?? ""}`,
        `Ángulo recomendado: ${j.angulo_recomendado ?? ""}`,
        `Tipo contenido: ${j.tipo_contenido ?? ""}`,
        `Prioridad: ${j.prioridad ?? ""}`,
        `Potencial LinkedIn: ${j.potencial_linkedin ?? ""}`,
        `Potencial SEO: ${j.potencial_seo ?? ""}`,
        `Potencial NExprix: ${j.potencial_nexprix ?? ""}`,
        `Riesgo reputacional: ${j.riesgo_reputacional ?? ""}`,
      ].join("\n"),
    },
  },
];

// Nodo Code (Run Once for Each Item recomendado)

// 1) Leer texto del LLM
const root = $json;
const rawText = (
  root.text ??
  root.content?.parts?.[0]?.text ??
  root.output_text ??
  ""
).toString();

// 2) Extraer bloque JSON
const firstBrace = rawText.indexOf("{");
const lastBrace = rawText.lastIndexOf("}");
let jsonCandidate =
  firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace
    ? rawText.slice(firstBrace, lastBrace + 1)
    : rawText;

// 3) Parse robusto
let content = {};
try {
  content = JSON.parse(jsonCandidate);
} catch {
  try {
    const repaired = jsonCandidate.replace(/,\s*([}\]])/g, "$1");
    content = JSON.parse(repaired);
  } catch {
    content = {};
  }
}

// 4) Normalización de campos
const linkedin_draft = content.linkedin_draft || content.linkedin_content || "";
let blog_draft = content.blog_draft || content.blog_content || "";

// NUEVO: título sugerido por el LLM (si lo devuelve)
const llmTitle =
  content.blog_title ||
  content.seo_title ||
  content.title ||
  "";

const image_subject =
  content.image_subject ||
  content.imageSubject ||
  content.subject ||
  "";

const image_theme =
  content.image_theme ||
  content.imageTheme ||
  content.theme ||
  "";

let image_keywords =
  content.image_keywords ||
  content.imageKeywords ||
  content.keywords ||
  [];

if (typeof image_keywords === "string") {
  image_keywords = image_keywords.split(",").map(s => s.trim()).filter(Boolean);
}
if (!Array.isArray(image_keywords)) image_keywords = [];
image_keywords = image_keywords.map(k => String(k).trim()).filter(Boolean).slice(0, 10);

// 5) Título final
let originalTitle =
  llmTitle ||
  root.original_title ||
  root.topic_title ||
  root.title ||
  "";

if (!originalTitle || originalTitle === "Borrador Automático") {
  const candidate =
    (blog_draft || linkedin_draft || "")
      .replace(/<[^>]+>/g, " ")
      .replace(/\s+/g, " ")
      .trim()
      .split(/[.!?]/)[0]
      .trim();

  originalTitle = candidate ? candidate.slice(0, 90) : "Artículo";
}

// NUEVO: limpiar duplicado de título en blog
function normalizeText(str) {
  return String(str || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/<[^>]+>/g, " ")
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

// Quitar H1 inicial siempre (WP ya pinta título)
blog_draft = blog_draft.replace(/^\s*<h1\b[^>]*>[\s\S]*?<\/h1>\s*/i, "");

// Quitar primer H2 si repite el título
const firstH2 = blog_draft.match(/^\s*<h2\b[^>]*>([\s\S]*?)<\/h2>\s*/i);
if (firstH2) {
  const h2Text = normalizeText(firstH2[1]);
  const titleText = normalizeText(originalTitle);
  if (h2Text === titleText || h2Text.includes(titleText) || titleText.includes(h2Text)) {
    blog_draft = blog_draft.replace(/^\s*<h2\b[^>]*>[\s\S]*?<\/h2>\s*/i, "");
  }
}
blog_draft = blog_draft.trim();

// 6) Prompt imagen
const STYLE_PROMPT =
  "A realistic subject illustrated in the style of the iPad app Paper by FiftyThree. " +
  "The subject must be a real, recognizable thing from the real world (animal, person, object, or everyday scene), not a metaphor, not an abstract concept. " +
  "Hand-sketched watercolor look with loose pencil and ink lines, imperfect strokes, soft watercolor washes, and an off-white paper background. " +
  "Paper53 style as an aesthetic, not a drawing action. " +
  "No hands, no people, no body parts, no drawing tools. " +
  "No robots, no mechanical parts, no futuristic or sci-fi aesthetics. " +
  "No diagrams, no mind maps, no abstract symbols. " +
  "Text is optional and secondary; if present, use only real, common words related to the topic. " +
  "No invented words, no pseudo-text, no filler. " +
  "Calm, human, organic, editorial tone.";

const subjectFinal = image_subject || `a real-world subject related to: ${originalTitle}`;
const themeFinal = image_theme || "";
const keywordsFinal = image_keywords.length ? image_keywords.join(", ") : "";

const finalImagePrompt = (
  `${STYLE_PROMPT}\n\n` +
  `Main subject: ${subjectFinal}.\n` +
  (themeFinal ? `Theme/context: ${themeFinal}.\n` : "") +
  (keywordsFinal ? `Optional real words (if used, short): ${keywordsFinal}.\n` : "") +
  "Prefer the image to work even with no text."
).slice(0, 999);

// 7) Salida
return [
  {
    json: {
      ...root,
      title: originalTitle,
      linkedin_draft,
      blog_draft,
      image_subject: subjectFinal,
      image_theme: themeFinal,
      image_keywords,
      image_prompt: finalImagePrompt
    }
  }
];

const topic = $input.first().json;
const payload = $items("Edit Fields", 0, 0)[0]?.json ?? {};

const telegramUserId = payload.telegram_user_id ?? null;
const telegramChatId = payload.telegram_chat_id ?? null;
const choice = payload.choice ?? null;
const fechaDigest = payload.fecha_digest ?? null;
const selectedText = payload.selected_text ?? null;

if (!telegramUserId) {
  throw new Error("telegram_user_id vacío en Edit Fields");
}

return [
  {
    json: {
      telegram_user_id: String(telegramUserId),
      telegram_chat_id: telegramChatId ? String(telegramChatId) : null,
      fecha_digest: topic.fecha_digest ?? fechaDigest ?? $now.setZone("Europe/Madrid").toFormat("yyyy-LL-dd"),
      rank_dia: Number(topic.rank_dia ?? choice),
      content_topic_id: topic.id,
      selected_text: selectedText ?? (choice !== null ? String(choice) : ""),
    },
  },
];
